-- Change operation_id from TEXT to INTEGER. The values are generated by a
-- monotonic uint64 sequence (domain/sequence/state/sequence.go:24) and were
-- previously stringified before storage. Storing as INTEGER matches the true
-- type and fixes lexicographic-vs-numeric ordering of ORDER BY operation_id
-- (domain/operation/state/query.go:307) once IDs reach double digits.
CREATE TABLE operation_new (
    uuid TEXT NOT NULL PRIMARY KEY,
    operation_id INTEGER NOT NULL,
    summary TEXT,
    enqueued_at TIMESTAMP NOT NULL,
    started_at TIMESTAMP,
    completed_at TIMESTAMP,
    parallel BOOLEAN DEFAULT false,
    execution_group TEXT
);

INSERT INTO operation_new (uuid, operation_id, summary, enqueued_at, started_at,
                           completed_at, parallel, execution_group)
SELECT uuid, CAST(operation_id AS INTEGER), summary, enqueued_at, started_at,
       completed_at, parallel, execution_group
FROM operation;

DROP TABLE operation;
ALTER TABLE operation_new RENAME TO operation;

CREATE UNIQUE INDEX idx_operation_id
ON operation (operation_id);
